int myAtoi(char* s) {
    int i = 0, sign = 1;
    long res = 0;
    while (s[i] == ' ') i++;
    if (s[i] == '+' || s[i] == '-') { sign = s[i++] == '-' ? -1 : 1; }
    while (s[i] >= '0' && s[i] <= '9') {
        res = res * 10 + (s[i++] - '0');
        if (sign * res >= 2147483647) return 2147483647;
        if (sign * res <= -2147483648L) return -2147483648;
    }
    return (int)(sign * res);
}

