class Solution {
public:
    int myAtoi(string s) {
        int i = 0, sign = 1;
        long res = 0;
        while (i < (int)s.size() && s[i] == ' ') i++;
        if (i < (int)s.size() && (s[i] == '+' || s[i] == '-')) sign = s[i++] == '-' ? -1 : 1;
        while (i < (int)s.size() && isdigit(s[i])) {
            res = res * 10 + (s[i++] - '0');
            if (sign * res >= INT_MAX) return INT_MAX;
            if (sign * res <= INT_MIN) return INT_MIN;
        }
        return (int)(sign * res);
    }
};
